mapper.select:
select id, celebrity_id, category_id, category_name, sale_score, sale_num, followers_num, product_title, product_image_url, sale_date, sale_image_url, remark, create_by, create_time, update_by, update_time, category_parent_id, category_parent_name
FROM store_sale_result
and category_parent_id = #{storeSaleResultModel.categoryParentId}
and celebrity_id = #{storeSaleResultModel.celebrityId}
and category_id = #{storeSaleResultModel.categoryId}
and product_title like '%${storeSaleResultModel.productTitle}%'
and sale_num >= #{storeSaleResultModel.saleStartNum}
and sale_num <= #{storeSaleResultModel.saleEndNum}
and DATE_FORMAT(sale_date, '%Y-%m-%d') >= DATE_FORMAT(#{storeSaleResultModel.startSaleDate}, '%Y-%m-%d')
and DATE_FORMAT(sale_date, '%Y-%m-%d') <= DATE_FORMAT(#{storeSaleResultModel.endSaleDate}, '%Y-%m-%d')
/*and id IN ( SELECT user_id FROM store_level GROUP BY user_id)*/
